        if remaining_bricks == 0:
            self.combinations.append(current_combination)
            return
        for i in range(start, self.brick_count + 1):
            self.generate_combinations(current_combination + [i], remaining_bricks - 1, i)

    def verify_claim(self):
        self.generate_combinations([], self.brick_count, 1)
        return len(self.combinations) == 915

    def classify_combination(self, combination):
        if len(combination) <= 2:
