class BrickCombiner:
    def __init__(self, stock_bricks):
        self.stock_bricks = stock_bricks
        self.combinations = []

    def generate_combinations(self, current_combination, remaining_bricks, start):
        if remaining_bricks == 0:
            self.combinations.append(current_combination.copy())
            return
        for i in range(start, len(self.stock_bricks)):
            if self.stock_bricks[i] <= remaining_bricks:
                current_combination.append(self.stock_bricks[i])
                self.generate_combinations(current_combination, remaining_bricks - self.stock_bricks[i], i)
                current_combination.pop()

    def verify_claim(self, target):
        self.generate_combinations([], self.stock_bricks, 0)
        return len(self.combinations) == target

    def classify_combination(self, combination):
        if len(combination) <= 3:
            return "Trivial"
        elif len(combination) <= 6:
            return "Moderate"
        else:
            return "Complicated"

