class LegoCombiner:
    def __init__(self):
        self.brick_size = (2, 4)
        self.brick_count = 6
        self.combinations = []

    def generate_combinations(self, current_combination, remaining_bricks, start):
        if remaining_bricks == 0:
            self.combinations.append(current_combination)
            return
        for i in range(start, self.brick_count + 1):
            self.generate_combinations(current_combination + [i], remaining_bricks - 1, i)

    def verify_claim(self):
        self.generate_combinations([], self.brick_count, 1)
        return len(self.combinations)

    def classify_combination(self, combination):
        if len(combination) <= 3:
            return "Trivial"
        elif len(combination) <= 5:
            return "Moderate"
        else:
            return "Complicated"

    def adjudicate_combinations(self):
        results = {}
        for i in range(1, self.brick_count + 1):
            combination = [self.brick_size] * i
            results[tuple(combination)] = self.classify_combination(combination)
        return results


