from itertools import combinations

class BrickCombination:
    def __init__(self, bricks):
        self.bricks = bricks
        self.combinations = []
        self.trivial_count = 0
        self.complicated_count = 0

    def generate_combinations(self):
        for r in range(1, len(self.bricks) + 1):
            self.combinations.extend(combinations(self.bricks, r))

    def classify_combinations(self):
        for combo in self.combinations:
            if self.is_trivial(combo):
                self.trivial_count += 1
            else:
                self.complicated_count += 1

    def is_trivial(self, combo):
        # Define trivial as combinations that can be formed by simple stacking
        return len(combo) == 1 or all(brick == combo[0] for brick in combo)

    def get_classification(self):
        return {
            "trivial": self.trivial_count,
            "complicated": self.complicated_count
        }

def verify_legos_claim():
    bricks = ['2x4'] * 6
    lego_combination = BrickCombination(bricks)
    lego_combination.generate_combinations()
    lego_combination.classify_combinations()
    classification = lego_combination.get_classification()

    total_combinations = classification['trivial'] + classification['complicated']
    claim_verified = total_combinations == 915  # Adjust this number based on the claim

    return claim_verified, classification

