    def __init__(self, target):
        self.target = target
        self.combinations = []
        self.trivial_count = 0
        self.complicated_count = 0

    def find_combinations(self, current_combination, remaining, start):
        if remaining == 0:
            self.combinations.append(current_combination.copy())
            if len(current_combination) == 1:
                self.trivial_count += 1
            else:
                self.complicated_count += 1
            return
        for i in range(start, self.target + 1):
            if i <= remaining:
                current_combination.append(i)
                self.find_combinations(current_combination, remaining - i, i)
                current_combination.pop()

    def classify_combinations(self):
        self.find_combinations([], self.target, 1)
        return self.combinations, self.trivial_count, self.complicated_count

